mapper.select:
select id, tenant_id as tenantId, entity_type as entityType, entity_id as entityId,
       before_json as beforeJson, after_json as afterJson, create_by as createBy, create_time as createTime
from spd_foundation_data_snapshot
where tenant_id = #{tenantId}
and entity_type = #{entityType}
and entity_id = #{entityId}
order by create_time desc
limit 200
